def generate_session_token(user_id):
    ts = str(int(time.time()))
    msg = f"{user_id}:{ts}".encode()
    sig = hmac.new(app.secret_key.encode(), msg, hashlib.sha256).digest()
    token = base64.urlsafe_b64encode(msg + b":" + sig).decode()
